// ─── Helpers ─────────────────────────────────────────────────────────────────

function buildSetMetadataCall(address, meta) {
  return {
    contract: { address, name: "Token" },
    method: "setMetadata",
    args: {
      _description: meta.description,
      _images:      meta.images,
      _files:       meta.files,
      _fileNames:   meta.fileNames,
    },
    txParams: {
      gasPrice: config.gasPrice,
      gasLimit: config.gasLimit,
    },
  };
}

function parseArgs() {
  return { apply: process.argv.includes("--apply") };
}

// ─── Main ────────────────────────────────────────────────────────────────────

async function main() {
  const { apply } = parseArgs();

  const entries = TARGETS.map((address) => {
    const meta = METADATA[address];
    if (!meta) throw new Error(`No metadata entry for address ${address}`);
    return { address, meta };
  });

  const plannedCalls = entries.map((e) => buildSetMetadataCall(e.address, e.meta));

  console.log("=== Token Metadata Update Plan ===\n");
  console.log(`Node URL: ${config.nodes?.[0]?.url || "(not set)"}`);
  console.log(`Mode:     ${apply ? "APPLY (live)" : "DRY RUN"}`);
  console.log(`Total:    ${entries.length} token(s)\n`);

  for (const e of entries) {
    console.log(`  ${e.address}  desc: "${e.meta.description.slice(0, 60)}…"  images: ${e.meta.images.length}`);
  }

  if (!apply) {
    console.log("\nDry run only. Planned calls:");
    console.log(JSON.stringify(plannedCalls, null, 2));
    console.log("\nRe-run with --apply to execute.");
    return;
  }

  const username = process.env.GLOBAL_ADMIN_NAME;
  const password = process.env.GLOBAL_ADMIN_PASSWORD;
  if (!username || !password) {
    throw new Error("GLOBAL_ADMIN_NAME and GLOBAL_ADMIN_PASSWORD are required");
  }

  console.log(`\nAuthenticating as ${username}...`);
  const token = await auth.getUserToken(username, password);
  const tokenObj = { token };
  console.log(`Authenticated as ${username}\n`);

  let successCount = 0;
  let failCount = 0;

  for (let i = 0; i < entries.length; i++) {
    const { address, meta } = entries[i];
    const call = plannedCalls[i];

    console.log(`\n--- [${i + 1}/${entries.length}] ${address} ---`);
    console.log(`  description: "${meta.description.slice(0, 80)}…"`);
    console.log(`  images: ${meta.images.length}  files: ${meta.files.length}`);

    let ok = false;
    for (let attempt = 1; attempt <= 3; attempt++) {
      try {
        const result = await rest.call(tokenObj, call, { config, cacheNonce: true });
        console.log(`  [OK] ${JSON.stringify(result)}`);
        ok = true;
        break;
      } catch (err) {
        console.error(`  [FAIL attempt ${attempt}/3] ${err.message}`);
        if (attempt < 3) {
          console.log(`  Waiting 10s before retry...`);
          await new Promise((r) => setTimeout(r, 10000));
        }
      }
    }
    if (ok) successCount++;
    else failCount++;
  }

  console.log(`\n=== Done. ${successCount}/${entries.length} succeeded, ${failCount} failed. ===`);
  if (failCount > 0) process.exit(1);
}

if (require.main === module) {
  main().catch((error) => {
    console.error("update-token-metadata failed:", error.message);
    process.exit(1);
  });
}

module.exports = { main };
